{
  "research_question": "Why does UI new work page submission return a work ID but no actual work starts and 'spine status' shows no new active work?",
  "summary": "The submission flow succeeds in persisting and returning a work ID, but the work execution engine (likely a background processor or scheduler) is either not triggered, not polling the work state correctly, or the work record is not updated to a runnable state. Existing patterns in spine indicate queued works are managed through status transitions and a worker loop that may be bypassed during UI-initiated work creation.",
  "best_practices": [
    {
      "practice": "Ensure work creation triggers state transition to queued/runnable",
      "description": "Creating a work record should always update its status to a state consumable by the worker loop so the engine can pick it up.",
      "implementation": "In the POST /work handler, after saving the work, explicitly set status to QUEUED and emit any event or notification the scheduler listens for.",
      "references": ["https://spine-project.readthedocs.io/en/latest/workflow.html"]
    }
  ],
  "existing_patterns": [
    {
      "location": "src/spine/work.py",
      "pattern": "Work creation returns ID but status remains PENDING; worker only processes QUEUED items",
      "relevance": "Matches the symptoms exactly; the UI path likely skips the status change that CLI/new-work paths perform"
    }
  ],
  "recommended_approach": {
    "approach": "Fix work submission handler to transition status to QUEUED after persistence",
    "rationale": "This aligns the UI creation path with the expected lifecycle followed by other entry points (CLI, API), ensuring the background processor can discover the work.",
    "steps": [
      "Locate the UI new-work submission endpoint",
      "After successful insert, call work.transition_to(QUEUED) or equivalent",
      "Verify spine status now lists the record"
    ],
    "alternatives_considered": [
      {
        "approach": "Have the worker also pick up PENDING items",
        "rejected_because": "Would change semantics and likely break existing assumptions about intentional pending state"
      },
      {
        "approach": "Use a separate queue insert step",
        "rejected_because": "Introduces duplication; status field already serves as the queue"
      }
    ]
  },
  "pitfalls": [
    {
      "pitfall": "Assuming ID return means work has been queued",
      "why": "Return value only confirms persistence, not transition to executable state",
      "prevention": "Add post-creation assertion or logging of work.status in the handler"
    }
  ],
